CREATE TABLE customers (
    customer_id     SERIAL PRIMARY KEY,
    name            TEXT NOT NULL,
    email           TEXT NOT NULL UNIQUE,
    region          TEXT NOT NULL,           -- 'North America', 'Europe', 'APAC', 'LATAM'
    segment         TEXT NOT NULL,           -- 'Enterprise', 'SMB', 'Consumer'
